import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";


const FAQS = [
  { q: "How many days are between two dates?", a: "Subtract the earlier date from the later date in milliseconds, then divide by (1000  x  60  x  60  x  24). This calculator does that automatically and also shows the result in weeks, months, and years." },
  { q: "Does the calculator include or exclude the end date?", a: "This calculator counts exclusive of the end date by default (the standard mathematical convention). To include both start and end dates, add 1 to the result." },
  { q: "How do I calculate a date X days from now?", a: "Use the 'Add/Subtract Days' mode: select today as the start date and enter the number of days to add. The calculator will show the resulting future date." },
  { q: "How many business days are between two dates?", a: "Business days exclude Saturdays and Sundays (and sometimes holidays). A rough estimate is to multiply calendar days by 5/7. For example, 14 calendar days - 10 business days." },
  { q: "How do I calculate how many days until a future date?", a: "Enter today as the start date and your target date as the end date. The calculator will show the number of calendar days remaining. You can also switch to 'Add/Subtract Days' mode to find a date exactly N days in the future." },
  { q: "What is the difference between calendar days and business days?", a: "Calendar days count every day including weekends and holidays. Business days count only Monday-Friday, excluding weekends. For contract deadlines and shipping estimates, always clarify which type of days is meant." },
  { q: "How do I find what date is 90 days from today?", a: "Switch to 'Add/Subtract Days' mode, set the start date to today, enter 90 in the days field, and select 'Add.' The result is the date exactly 90 calendar days from today." },
];

type Mode = "diff" | "add";

export default function DateCalculator() {
  const today = new Date().toISOString().split("T")[0];
  const [mode, setMode] = useState<Mode>("diff");
  const [date1, setDate1] = useState(today);
  const [date2, setDate2] = useState(today);
  const [daysToAdd, setDaysToAdd] = useState(30);
  const [operation, setOperation] = useState<"add" | "sub">("add");

  const d1 = new Date(date1);
  const d2 = new Date(date2);
  const diffMs = Math.abs(d2.getTime() - d1.getTime());
  const diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24));
  const diffWeeks = (diffDays / 7).toFixed(1);
  const diffMonths = (diffDays / 30.44).toFixed(1);
  const diffYears = (diffDays / 365.25).toFixed(2);

  const resultDate = new Date(d1.getTime() + (operation === "add" ? 1 : -1) * daysToAdd * 24 * 3600000);
  const fmtDate = (d: Date) => d.toLocaleDateString("en-US", { weekday: "long", year: "numeric", month: "long", day: "numeric" });

  return (
    <>
      <SEOHead
        title="Free Date Calculator Online - Calculate Days Between Dates Instantly | CalcHive"
        description="Free online date calculator. Calculate days between two dates or add and subtract days from any date instantly. 100% free for everyone, no signup required."
        canonical="/date-calculator"
        keywords="free date calculator, days between dates calculator free online, date difference calculator free, add subtract days from date free, free calendar calculator"
        category="Date & Time Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-slate-600 dark:text-slate-400 bg-slate-100 dark:bg-slate-800/50 px-3 py-1 rounded-full mb-4 inline-block">Tools</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Date Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free date calculator to find days between dates or add subtract days from date free. This days between dates calculator free online also works as a date difference calculator free and free calendar calculator.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="flex gap-2 mb-6">
            <button onClick={() => setMode("diff")} className={`px-4 py-1.5 rounded-full text-sm font-semibold border transition-all ${mode === "diff" ? "bg-primary text-primary-foreground border-primary" : "bg-muted text-muted-foreground border-border"}`}>Date Difference</button>
            <button onClick={() => setMode("add")} className={`px-4 py-1.5 rounded-full text-sm font-semibold border transition-all ${mode === "add" ? "bg-primary text-primary-foreground border-primary" : "bg-muted text-muted-foreground border-border"}`}>Add / Subtract Days</button>
          </div>
          {mode === "diff" ? (
            <div className="grid sm:grid-cols-2 gap-4 mb-8">
              {[{ id: "d1", label: "Start Date", val: date1, set: setDate1 }, { id: "d2", label: "End Date", val: date2, set: setDate2 }].map(({ id, label, val, set }) => (
                <div key={id}>
                  <label htmlFor={id} className="text-sm font-semibold text-foreground block mb-2">{label}</label>
                  <input id={id} type="date" value={val} onChange={e => set(e.target.value)} className="w-full px-3 py-2.5 rounded-xl border border-input bg-background text-foreground focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all" />
                </div>
              ))}
            </div>
          ) : (
            <div className="space-y-4 mb-8">
              <div>
                <label className="text-sm font-semibold text-foreground block mb-2">Start Date</label>
                <input type="date" value={date1} onChange={e => setDate1(e.target.value)} className="w-full sm:w-auto px-3 py-2.5 rounded-xl border border-input bg-background text-foreground focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all" />
              </div>
              <div className="flex gap-2">
                <button onClick={() => setOperation("add")} className={`px-4 py-1.5 rounded-full text-sm font-semibold border transition-all ${operation === "add" ? "bg-primary text-primary-foreground border-primary" : "bg-muted text-muted-foreground border-border"}`}>+ Add</button>
                <button onClick={() => setOperation("sub")} className={`px-4 py-1.5 rounded-full text-sm font-semibold border transition-all ${operation === "sub" ? "bg-primary text-primary-foreground border-primary" : "bg-muted text-muted-foreground border-border"}`}>- Subtract</button>
              </div>
              <div className="flex items-center gap-3">
                <input type="number" value={daysToAdd} min={1} onChange={e => setDaysToAdd(Number(e.target.value))} className="w-24 px-3 py-2 rounded-lg border border-input bg-background text-foreground font-bold focus:outline-none focus:ring-2 focus:ring-primary/40" />
                <span className="text-sm text-muted-foreground">days</span>
              </div>
            </div>
          )}
          <motion.div key={`${mode}-${date1}-${date2}-${daysToAdd}-${operation}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            {mode === "diff" ? (
              <>
                <div className="bg-gradient-to-br from-slate-600 to-slate-800 rounded-2xl p-6 mb-4 text-center shadow-lg">
                  <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Days Between Dates</p>
                  <p className="text-6xl font-black text-white tracking-tight" data-testid="result-days">{diffDays.toLocaleString()}</p>
                  <p className="text-white/70 text-sm mt-1">days</p>
                </div>
                <div className="grid grid-cols-3 gap-3">
                  {[{ label: "Weeks", value: diffWeeks }, { label: "Months", value: diffMonths }, { label: "Years", value: diffYears }].map(({ label, value }) => (
                    <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center hover:shadow-sm transition-shadow">
                      <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                      <p className="text-lg font-extrabold text-foreground">{value}</p>
                    </div>
                  ))}
                </div>
              </>
            ) : (
              <div className="bg-gradient-to-br from-slate-600 to-slate-800 rounded-2xl p-6 text-center shadow-lg">
                <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Resulting Date</p>
                <p className="text-2xl font-black text-white tracking-tight" data-testid="result-date">{fmtDate(resultDate)}</p>
              </div>
            )}
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Days Between Two Dates for Free</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Time Period", "Calendar Days", "Business Days (approx.)"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["1 week", "7 days", "5 days"],
                  ["2 weeks", "14 days", "10 days"],
                  ["1 month", "28-31 days", "20-23 days"],
                  ["Quarter (3 months)", "90-92 days", "64-66 days"],
                  ["6 months", "181-184 days", "130-132 days"],
                  ["1 year", "365 days (366 in leap year)", "261 days"],
                  ["5 years", "1,826 days (1,827 if includes leap year)", "1,305 days"],
                ].map(([period, cal, biz]) => (
                  <tr key={period} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{period}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{cal}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{biz}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How to Add and Subtract Days From Any Date</h2>
          <ul className="space-y-2 text-muted-foreground list-disc list-inside">
            <li><strong className="text-foreground">Contract deadlines:</strong> If a contract gives you 30 days to respond, count from the day after receipt (day 0 = receipt day, day 30 = deadline).</li>
            <li><strong className="text-foreground">Return windows:</strong> A "30-day return policy" typically starts from the purchase date. Enter the purchase date + 30 days to find the exact return deadline.</li>
            <li><strong className="text-foreground">Warranty periods:</strong> For a 1-year warranty starting today, the calculator will show the exact expiry date when you add 365 days.</li>
            <li><strong className="text-foreground">Pregnancy due date:</strong> Use "Add Days" mode: enter last menstrual period date + 280 days (40 weeks) to estimate due date.</li>
            <li><strong className="text-foreground">Shipping estimates:</strong> Add estimated transit days to the ship date to see the expected delivery window.</li>
          </ul>
        </section>

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">Free Date Difference Calculator for Everyone</h2>
          <p className="text-muted-foreground leading-relaxed">Use this free date and time tool on any device to compare schedules, track durations, and get instant results without signup.</p>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/date-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


